#include <bits/stdc++.h>
using namespace std;

vector<int> calculateSpan(vector<int>& prices) {
    int n = prices.size();
    vector<int> span(n);
    stack<int> st;  // Stack to store indices

    // First day's span is always 1
    span[0] = 1;
    st.push(0);

    // Calculate span for rest of the days
    for(int i = 1; i < n; i++) {
        // Pop elements from stack while stack is not empty
        // and top of stack is smaller than prices[i]
        while(!st.empty() && prices[st.top()] <= prices[i]) {
            st.pop();
        }

        // If stack becomes empty, span is i+1
        // else span is difference between current day and top of stack
        span[i] = st.empty() ? i + 1 : i - st.top();

        // Push current day to stack
        st.push(i);
    }

    return span;
}

int main() {
    int n;
    cin >> n;

    vector<int> prices(n);
    for(int i = 0; i < n; i++) {
        cin >> prices[i];
    }

    vector<int> result = calculateSpan(prices);

    for(int span : result) {
        cout << span << " ";
    }
    cout << endl;

    return 0;
}
